  "prompt": "Analyze this business inquiry and extract structured data:

Name: {{ $json.firstName }} {{ $json.lastName }}
Email: {{ $json.email }}
Company: {{ $json.company }}
Service Interest: {{ $json.service }}
Budget: {{ $json.budget }}
Timeline: {{ $json.timeline }}
Message: {{ $json.message }}

Extract and return ONLY valid JSON (no markdown, no code blocks):
{
  "intent": "website_redesign|new_website|consultation|maintenance|ecommerce|custom_app|automation|seo|other",
  "urgency": "immediate|1_month|1_3_months|3_6_months|exploring|unclear",
  "budget_signal": "low_under_5k|medium_5k_15k|high_15k_50k|enterprise_50k_plus|not_mentioned",
  "company_size": "solopreneur|small_1_10|medium_10_50|large_50_plus|enterprise_500_plus|unclear",
  "qualification_score": 0-100,
  "technical_complexity": "simple|moderate|complex|enterprise|unclear",
  "pain_points": ["array of 2-5 main problems"],
  "next_action": "send_pricing|schedule_call|send_portfolio|send_case_study|qualify_further|nurture",
  "sentiment": "enthusiastic|professional|frustrated|curious|skeptical",
  "summary": "one clear sentence summarizing the lead",
  "red_flags": ["any concerns like unrealistic budget, vague requirements, etc"],
  "opportunity_size": "small|medium|large|enterprise"
}",
  "stream": false,
  "format": "json"
}

parameters.jsCode:
// Parse AI response and extract JSON
const aiResponse = $input.item.json.response;
let aiAnalysis;

try {
  // Try to parse as JSON directly
  aiAnalysis = JSON.parse(aiResponse);
} catch (e) {
  // If that fails, try to extract JSON from markdown code blocks
  const jsonMatch = aiResponse.match(/```json\s*([\s\S]*?)\s*```/) || 
                    aiResponse.match(/```\s*([\s\S]*?)\s*```/) ||
                    aiResponse.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    aiAnalysis = JSON.parse(jsonMatch[1] || jsonMatch[0]);
  } else {
    throw new Error('Could not extract JSON from AI response');
  }
}

// Get lead data from previous node
const leadData = $('Set: Lead Data').item.json;

// Determine email sequence based on qualification score
let sequenceType;
if (aiAnalysis.qualification_score >= 70) {
  sequenceType = 'high_intent';
} else if (aiAnalysis.qualification_score >= 40) {
  sequenceType = 'qualified';
} else {
  sequenceType = 'nurture';
}

// Return combined data
return {
  json: {
    // Lead basic info
    firstName: leadData.firstName,
    lastName: leadData.lastName,
    email: leadData.email,
    company: leadData.company,
    message: leadData.message,
    service: leadData.service,
    budget: leadData.budget,
    timeline: leadData.timeline,
    source: leadData.source,
    timestamp: leadData.timestamp,

    // AI analysis
    ai_intent: aiAnalysis.intent,
    ai_urgency: aiAnalysis.urgency,
    ai_budget_signal: aiAnalysis.budget_signal,
    ai_company_size: aiAnalysis.company_size,
    ai_qualification_score: aiAnalysis.qualification_score,
    ai_technical_complexity: aiAnalysis.technical_complexity,
    ai_pain_points: JSON.stringify(aiAnalysis.pain_points),
    ai_next_action: aiAnalysis.next_action,
    ai_sentiment: aiAnalysis.sentiment,
    ai_summary: aiAnalysis.summary,
    ai_red_flags: JSON.stringify(aiAnalysis.red_flags || []),
    ai_opportunity_size: aiAnalysis.opportunity_size,
    raw_ai_analysis: JSON.stringify(aiAnalysis),

    // Sequence type
    sequence_type: sequenceType,

    // For Qdrant ID
    lead_id: `${Date.now()}-${leadData.email.replace(/[^a-zA-Z0-9]/g, '-')}`
  }
};

